import React, { useState } from 'react';
import api from '../api/api';
import { FaUpload, FaCamera, FaSpinner, FaCheckCircle } from 'react-icons/fa';

// CalorieUpload receives fetchNutrientWarnings as a prop
const CalorieUpload = ({ profile, fetchNutrientWarnings }) => {
    
    const [mealType, setMealType] = useState(''); 
    const [uploadedImage, setUploadedImage] = useState(null); // Will store a boolean or string path when "uploaded"
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [uploadMessage, setUploadMessage] = useState('');

    // --- NEW: Simulate Image Selection/Upload ---
    const handleSimulateUpload = () => {
        setUploadedImage('mock_meal_photo.jpg'); // Set the state to signal an image is ready
        setUploadError('');
        setPrediction(null); // Clear previous prediction
    };
    // ------------------------------------------

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setUploadError('');
        setUploadMessage('');
        setPrediction(null);
        
        // --- VALIDATION: Must select meal type AND have an image ready ---
        if (!mealType) {
            setUploadError("Please select a Meal Type.");
            setLoading(false);
            return;
        }
        if (!uploadedImage) {
            setUploadError("Please simulate uploading an image first.");
            setLoading(false);
            return;
        }

        // --- Mocking Payload Creation ---
        const payload = {
            mealType,
            imageUrl: uploadedImage, 
            filename: uploadedImage, 
        };

        try {
            const response = await api.post('/intake/upload-image', payload);
            
            // Only set prediction after successful API response
            setPrediction(response.data.prediction); 
            setUploadMessage("Meal logged successfully!");

            // Trigger the nutrient check immediately
            if (fetchNutrientWarnings) {
                await fetchNutrientWarnings(); 
            }

        } catch (err) {
            console.error('Meal upload failed:', err);
            setUploadError(err.response?.data?.message || 'Failed to log meal. Is the Python service running on Port 5001?');
        } finally {
            setLoading(false);
            setUploadedImage(null); // Clear the image state after successful logging
        }
    };

    const isReadyToEstimate = mealType && uploadedImage;

    return (
        <div className="space-y-6">
            <p className="text-gray-400">
                Simulate uploading a meal image to estimate calorie and macro intake. This requires **two steps**: 1) Select a meal type and Upload, then 2) Click Estimate & Log.
            </p>

            <div className="bg-[#161B22] p-6 rounded-xl border border-[#2D333B] shadow-lg">
                <form onSubmit={handleSubmit} className="space-y-4">
                    
                    <div>
                        <label htmlFor="mealType" className="block text-sm font-medium text-gray-400 mb-1">Meal Type</label>
                        <select 
                            id="mealType"
                            value={mealType} 
                            onChange={(e) => {
                                setMealType(e.target.value);
                                setUploadedImage(null); // Reset image state if meal type changes
                            }}
                            className="select"
                        >
                            <option value="">-- Select Meal Type --</option> 
                            <option value="Breakfast">Breakfast</option>
                            <option value="Lunch">Lunch</option>
                            <option value="Dinner">Dinner</option>
                            <option value="Snack">Snack</option>
                        </select>
                    </div>
                    
                    {/* --- STEP 1: SIMULATED IMAGE UPLOAD --- */}
                    <div className="text-center p-6 border-2 border-dashed border-gray-700 rounded-lg">
                        {uploadedImage ? (
                            <>
                                <FaCheckCircle className="mx-auto text-4xl text-ai-green mb-2" />
                                <p className="text-sm text-ai-green font-semibold">Image Ready for Processing</p>
                                <p className="text-xs text-gray-500">You can now click 'Estimate & Log' below.</p>
                            </>
                        ) : (
                            <>
                                <FaCamera className="mx-auto text-4xl text-gray-500 mb-2" />
                                <p className="text-sm text-gray-400 mb-3">Click below to simulate image selection/upload:</p>
                                <button 
                                    type="button" 
                                    onClick={handleSimulateUpload}
                                    disabled={!mealType}
                                    className={`py-2 px-4 rounded font-medium text-sm transition-all ${!mealType ? 'bg-gray-500 text-gray-300 cursor-not-allowed' : 'bg-accent-blue hover:bg-ai-green hover:text-black text-white'}`}
                                >
                                    Simulate Upload
                                </button>
                            </>
                        )}
                    </div>
                    
                    {/* --- STEP 2: ESTIMATE & LOG MEAL --- */}
                    <button 
                        type="submit" 
                        disabled={loading || !isReadyToEstimate} 
                        className={`w-full p-3 rounded font-semibold shadow-md btn-primary flex items-center justify-center space-x-2 
                                    ${loading || !isReadyToEstimate ? 'opacity-50 cursor-not-allowed' : 'btn-primary'}`}
                    >
                        {loading ? (
                            <>
                                <FaSpinner className="animate-spin" />
                                <span>Analyzing Meal...</span>
                            </>
                        ) : (
                            <>
                                <FaUpload />
                                <span>Estimate & Log Meal</span>
                            </>
                        )}
                    </button>
                    
                    {uploadError && <p className="text-red-400 mt-2">{uploadError}</p>}
                </form>
            </div>
            
            {uploadMessage && <p className="text-ai-green font-medium">{uploadMessage}</p>}

            {/* Display Prediction Result (Only shown after successful submission) */}
            {prediction && (
                <div className="mt-4 p-4 border border-gray-700 rounded-lg bg-[#1E1E1E] space-y-2">
                    <h4 className="text-xl font-bold mb-2 text-yellow-400">Estimation Result</h4>
                    <p className="text-lg">Food Detected: <span className="font-semibold text-white">{prediction.foodName}</span></p>
                    <p className="text-lg">Estimated Calories: <span className="font-semibold text-ai-green">{prediction.caloriesEstimated} kcal</span></p>
                    
                    <h5 className="font-semibold text-gray-400 pt-2">Macro Breakdown:</h5>
                    <ul className="grid grid-cols-3 text-sm text-gray-300">
                        <li>Protein: <span className='font-semibold'>{prediction.macroBreakdown?.protein || 'N/A'}</span>g</li>
                        <li>Fat: <span className='font-semibold'>{prediction.macroBreakdown?.fat || 'N/A'}</span>g</li>
                        <li>Carbs: <span className='font-semibold'>{prediction.macroBreakdown?.carbohydrates || 'N/A'}</span>g</li>
                    </ul>
                </div>
            )}
        </div>
    );
};

export default CalorieUpload;
